const args = $json.arguments || {};
const weather = {
  islamabad: { temperature: '28 deg C', condition: 'Partly Cloudy', humidity: '55%' },
  karachi: { temperature: '34 deg C', condition: 'Hot and Sunny', humidity: '70%' },
  lahore: { temperature: '32 deg C', condition: 'Hazy', humidity: '60%' }
};
const city = String(args.city || 'Islamabad').toLowerCase();
return [{ json: { ...$json, result: { city: args.city || 'Islamabad', ...(weather[city] || weather.islamabad) } } }];

const args = $json.arguments || {};
const rates = { PKR: 1, USD: 278.5, GBP: 352, AED: 75.8 };
const from = String(args.from_currency || 'PKR').toUpperCase();
const to = String(args.to_currency || 'PKR').toUpperCase();
const amount = Number(args.amount || 0);
const pkr = amount * (rates[from] || 1);
const converted = pkr / (rates[to] || 1);
return [{ json: { ...$json, result: { original: `${amount} ${from}`, converted: `${converted.toFixed(2)} ${to}` } } }];

const args = $json.arguments || {};
const city = String(args.city || 'Lahore').toLowerCase();
const base = city === 'islamabad' ? 32000 : city === 'karachi' ? 26000 : 24000;
return [{ json: { ...$json, result: { city: args.city || 'Lahore', university: args.university || 'University area', monthly_room_cost: `PKR ${base.toLocaleString()}`, note: 'Shared hostel room estimate near campus.' } } }];

const args = $json.arguments || {};
const routes = { 'lahore-karachi': 7500, 'islamabad-lahore': 3200, 'islamabad-karachi': 9000 };
const fromCity = String(args.from_city || '').toLowerCase();
const toCity = String(args.to_city || '').toLowerCase();
const key = `${fromCity}-${toCity}`;
const reverse = `${toCity}-${fromCity}`;
const cost = routes[key] || routes[reverse] || 5000;
return [{ json: { ...$json, result: { route: `${args.from_city || 'Origin'} to ${args.to_city || 'Destination'}`, estimated_cost: `PKR ${cost.toLocaleString()}`, mode: 'Bus or economy train estimate' } } }];

const current = $items('Turn Counter').at(-1).json;
const args = $json.arguments || {};
const toolName = $json.tool_name;
const toolCallId = $json.tool_call_id || `${toolName}-${Date.now()}`;

const assistantMessage = {
  role: 'assistant',
  content: null,
  tool_calls: [{
    id: toolCallId,
    type: 'function',
    function: {
      name: toolName,
      arguments: JSON.stringify(args),
    },
  }],
};

const toolMessage = {
  role: 'tool',
  tool_call_id: toolCallId,
  content: JSON.stringify($json.result || {}),
};

return [{ json: {
  ...current,
  messages: [...(current.messages || []), assistantMessage, toolMessage],
  tool_calls: [...(current.tool_calls || []), { tool_name: toolName, arguments: args, result: $json.result || {} }],
} }];

const response = $json;
const message = response.choices?.[0]?.message || {};
const toolCall = message.tool_calls?.[0];
const current = $items('Turn Counter').at(-1).json;
const calls = current.tool_calls || [];

const stable = (value) => JSON.stringify(value || {}, Object.keys(value || {}).sort());
const collectedAnswer = (prefix = 'Final answer from collected tool results') => {
  if (!calls.length) return message.content || 'No final answer generated.';
  const details = calls.map((call) => `${call.tool_name}: ${JSON.stringify(call.result || {})}`).join('; ');
  return `${prefix}: ${details}`;
};

if (!toolCall || !toolCall.function?.name) {
  return [{ json: {
    route: 'final',
    final_answer: message.content || collectedAnswer(),
    tool_calls: calls,
    turn_count: current.turn_count || 0,
    messages: current.messages || [],
    llm_response: response
  } }];
}

let args = {};
try {
  args = JSON.parse(toolCall.function.arguments || '{}');
} catch (error) {
  args = {};
}

const requestedSignature = `${toolCall.function.name}:${stable(args)}`;
const isDuplicate = calls.some((call) => `${call.tool_name}:${stable(call.arguments)}` === requestedSignature);
if (isDuplicate || calls.length >= 4) {
  return [{ json: {
    route: 'final',
    final_answer: collectedAnswer('Stopped to avoid repeated tool calls'),
    tool_calls: calls,
    turn_count: current.turn_count || 0,
    messages: current.messages || [],
    llm_response: response
  } }];
}

return [{ json: {
  route: toolCall.function.name,
  tool_call_id: toolCall.id,
  tool_name: toolCall.function.name,
  arguments: args,
  llm_response: response
} }];
